<?php/** * Template part for displaying service inquiry form * * @package AquaLuxe */// Get service inquiry form options from theme customizer$show_inquiry_form = get_theme_mod('aqualuxe_show_service_inquiry_form', true);$inquiry_form_title = get_theme_mod('aqualuxe_service_inquiry_form_title', __('Interested in this service?', 'aqualuxe'));$inquiry_form_subtitle = get_theme_mod('aqualuxe_service_inquiry_form_subtitle', __('Fill out the form below and we\'ll get back to you as soon as possible.', 'aqualuxe'));$inquiry_form_shortcode = get_theme_mod('aqualuxe_service_inquiry_form_shortcode', '');// Check if inquiry form should be displayedif (!$show_inquiry_form) {    return;}?><div class="service-inquiry-form">    <div class="inquiry-form-header">        <?php if (!empty($inquiry_form_title)) : ?>            <h3 class="inquiry-form-title"><?php echo esc_html($inquiry_form_title); ?></h3>        <?php endif; ?>                <?php if (!empty($inquiry_form_subtitle)) : ?>            <div class="inquiry-form-subtitle"><?php echo esc_html($inquiry_form_subtitle); ?></div>        <?php endif; ?>    </div>        <div class="inquiry-form-content">        <?php        if (!empty($inquiry_form_shortcode)) {            echo do_shortcode($inquiry_form_shortcode);        } else {            // Default form if no shortcode is provided            ?>            <form id="service-inquiry-form" class="inquiry-form" method="post">                <div class="form-group">                    <label for="inquiry-name"><?php echo esc_html__('Your Name', 'aqualuxe'); ?> <span class="required">*</span></label>                    <input type="text" id="inquiry-name" name="inquiry-name" class="form-control" required>                </div>                                <div class="form-group">                    <label for="inquiry-email"><?php echo esc_html__('Your Email', 'aqualuxe'); ?> <span class="required">*</span></label>                    <input type="email" id="inquiry-email" name="inquiry-email" class="form-control" required>                </div>                                <div class="form-group">                    <label for="inquiry-phone"><?php echo esc_html__('Phone Number', 'aqualuxe'); ?></label>                    <input type="tel" id="inquiry-phone" name="inquiry-phone" class="form-control">                </div>                                <div class="form-group">                    <label for="inquiry-message"><?php echo esc_html__('Your Message', 'aqualuxe'); ?> <span class="required">*</span></label>                    <textarea id="inquiry-message" name="inquiry-message" class="form-control" rows="4" required></textarea>                </div>                                <div class="form-group">                    <input type="hidden" name="service_id" value="<?php echo get_the_ID(); ?>">                    <input type="hidden" name="service_title" value="<?php echo esc_attr(get_the_title()); ?>">                    <input type="hidden" name="action" value="aqualuxe_service_inquiry">                    <input type="hidden" name="nonce" value="<?php echo wp_create_nonce('aqualuxe_service_inquiry_nonce'); ?>">                    <button type="submit" class="btn btn-primary btn-block"><?php echo esc_html__('Send Inquiry', 'aqualuxe'); ?></button>                </div>                                <div class="form-response"></div>            </form>            <?php        }        ?>    </div></div>